INSERT INTO public.query_master (sql_key, query_text, return_type, description, created_at, updated_at, required_params, param_mapping, use_redis_yn, redis_ttl_sec) VALUES ('GET_CONTENT_LIST_PAGE', 'SELECT d.content_id AS "content_id", d.user_sqno AS "user_sqno", d.title AS "title", d.date AS "date", d.emotion AS "emotion", d.day_tag1 AS "tag1", d.day_tag2 AS "tag2", d.day_tag3 AS "tag3", d.content_status AS "content_status", d.reg_dt AS "reg_dt", CASE WHEN u.del_yn = ''Y'' THEN CONCAT(''del_'', d.user_id) ELSE d.user_id END AS "user_id" FROM content d LEFT JOIN users u ON d.user_sqno = u.user_sqno WHERE d.del_yn = ''N'' AND (NULLIF(CAST(:filterId AS VARCHAR), '''') IS NULL OR d.user_id = CAST(:filterId AS VARCHAR)) ORDER BY d.reg_dt DESC LIMIT CAST(COALESCE(NULLIF(CAST(:pageSize AS VARCHAR), ''''), ''5'') AS INTEGER) OFFSET CAST(COALESCE(NULLIF(CAST(:offset AS VARCHAR), ''''), ''0'') AS INTEGER)', 'MULTI', '콘텐츠 목록 페이징 조회', '2026-01-14 23:10:06.713005', '2026-03-02 14:16:26.460792', NULL, '{"offset": "params.offset", "userId": "params.userId", "pageSize": "params.pageSize"}', 'Y', 300);
